def process_graph(graph_data):
    graph_copy = graph_data.copy()
    control_node = None
    for node, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a3.dom' and 'EK_CONTROL_DOMAIN' in attrs.get('type', []):
            control_node = node
            break
    if control_node is None:
        result = []
    else:
        children = []
        for neighbor in graph_copy.successors(control_node):
            if graph_copy[control_node][neighbor].get('type') == 'RK_CONTAINS':
                children.append(neighbor)
        child_capacity_list = []
        for child in children:
            total_capacity = 0
            queue = [child]
            visited = set([child])
            while queue:
                current = queue.pop(0)
                if 'EK_PORT' in graph_copy.nodes[current]['type']:
                    cap = graph_copy.nodes[current].get('physical_capacity_bps', 0)
                    total_capacity += cap
                for next_node in graph_copy.successors(current):
                    if graph_copy[current][next_node].get('type') == 'RK_CONTAINS' and next_node not in visited:
                        visited.add(next_node)
                        queue.append(next_node)
            child_name = graph_copy.nodes[child]['name']
            child_capacity_list.append((child_name, total_capacity))
        child_capacity_list.sort(key=lambda x: x[1], reverse=True)
        result = child_capacity_list
    return {
        'type': 'list',
        'data': result,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }

