    graph_copy = nx.DiGraph(graph_data)
    parent_node = None
    for node_id, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.s3.dom':
            parent_node = node_id
            break
    if parent_node is None:
        return {'type': 'list', 'data': [], 'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)}

