    for neighbor in graph_copy.successors(parent_node):
        edge_attrs = graph_copy[parent_node][neighbor]
        if edge_attrs.get('type') == 'RK_CONTAINS':
            children.append(neighbor)

    child_capacity_list = []
    for child in children:
        visited = set([child])
        queue = [child]
        total_capacity = 0
        while queue:
            current = queue.pop(0)
            for neighbor in graph_copy.successors(current):
                edge_attrs = graph_copy[current][neighbor]
                if edge_attrs.get('type') == 'RK_CONTAINS' and neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
                    if 'EK_PORT' in graph_copy.nodes[neighbor].get('type', []):
