def process_graph(graph_data):
    graph_copy = graph_data.copy()
    target_node = None
    for node, attr in graph_copy.nodes(data=True):
        if attr['name'] == 'ju1.a1.m3.s2c4' and 'EK_PACKET_SWITCH' in attr['type']:
            target_node = node
            break
    if target_node is None:
        new_node_name = 'new_EK_PORT_29'
        graph_copy.add_node(new_node_name, type=['EK_PORT'], physical_capacity_bps=0)
        graph_copy.add_edge(target_node, new_node_name, type='RK_CONTAINS')
        count = 1
    else:
        new_node_name = 'new_EK_PORT_29'
        graph_copy.add_node(new_node_name, type=['EK_PORT'], physical_capacity_bps=0)
        graph_copy.add_edge(target_node, new_node_name, type='RK_CONTAINS')
        count = 0
        for neighbor in graph_copy.neighbors(target_node):
            edge_data = graph_copy[target_node][neighbor]
            if edge_data['type'] == 'RK_CONTAINS' and 'EK_PORT' in graph_copy.nodes[neighbor]['type']:
                count += 1
    return_object = {
        'type': 'text',
        'data': str(count),
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object
